<?php
 namespace App\Models; use Illuminate\Database\Eloquent\Model; class TrainerInvoice extends Model { protected $fillable = [ 'invoice_no', 'member_id', 'trainer_id', 'trainer_type', 'session_title', 'session_days', 'fee', 'discount_percent', 'discount_amount', 'total', 'payment_method_id', 'start_date', 'end_date', 'invoice_header', 'invoice_footer', 'status', ]; protected $casts = [ 'fee' => 'decimal:2', 'discount_percent' => 'decimal:2', 'discount_amount' => 'decimal:2', 'total' => 'decimal:2', 'start_date' => 'date', 'end_date' => 'date', ]; public function member() { return $this->belongsTo(Member::class); } public function trainer() { return $this->belongsTo(Trainer::class); } public function paymentMethod() { return $this->belongsTo(PaymentMethod::class); } } 